#include <iostream>

static int callCount { 0 };

void recordCall()
{
    ++callCount;
}

int main()
{
    recordCall();
    recordCall();
    recordCall();
    recordCall();
    recordCall();
    std::cout << "Called: " << callCount << '\n';
    return 0;
}

