solution_code:
#include <iostream>

static const int discount { 30 };

int applyDiscount(int price)
{
    int result { price - discount };
    if (result < 0)
        return 0;
    return result;
}

int main()
{
    int price {};
    std::cin >> price;
    std::cout << applyDiscount(price) << '\n';
    return 0;
}
